sql:
SELECT w.domain, t.tld_name, w.category
FROM websites w
JOIN tlds t ON w.tld = t.tld_name;

SELECT category, COUNT(DISTINCT domain) AS count_of_domains
FROM websites
GROUP BY category;

SELECT domain, title 
FROM websites 
WHERE website_id < 1000 AND language = 'English';

external_knowledge:
- Blossoms: Total websites for each TLD;
- Bear fruit: Websites have rankings;
- Bees: Referrals to websites;
- Unvisited paths: Websites with no access records;
- Types of soil: Different TLDs (Top-Level Domains).
